function check_initializeAlphaIndices_callable_by_allowedCaller(address caller) public {
    // Setup: caller is the allowedCaller but not the owner
    vm.assume(caller == entropyGenerator.allowedCaller());
    vm.assume(caller != entropyGenerator.owner());
    vm.assume(caller != address(0));

    vm.prank(caller);
    // BUG: This will revert because onlyOwner modifier blocks allowedCaller
    // FIXED: Should succeed because allowedCaller should be permitted
    try entropyGenerator.initializeAlphaIndices() {
        // Expected: should succeed
        assert(true);
    } catch {
        // Bug: reverts when called by allowedCaller
        assert(false);
    }
}
